'use client';

import Link from 'next/link';
import { useEffect, useState } from 'react';
import { IoClose } from 'react-icons/io5';
import { FaInstagram, FaLinkedinIn } from 'react-icons/fa';
import Image from "next/image";
import logo from "@/assets/logo_desktop.jpg";

import './navbar.scss';

const menuItems = [
  { label: 'Início', href: '#' },
  { label: 'Sobre', href: '#' },
  { label: 'Projetos', href: '#' },
  { label: 'Serviços', href: '#' },
  { label: 'Contato', href: '#' },
];

export default function Header() {
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    document.body.style.overflow = isOpen ? 'hidden' : 'auto';

    return () => {
      document.body.style.overflow = 'auto';
    };
  }, [isOpen]);

  return (
    <>
      <header className='header'>
        <div className='container'>
          {/* LEFT */}
          <div className='left'>
            {/* DESKTOP LOGO */}
            <Link href="/" className='logoWrapper'>
              <Image
                src={logo}
                alt="Logo Exitus Engenharia"
                width={220}
                height={60}
                priority
              />
            </Link>

            {/* MOBILE BUTTON */}
            <button
              className='menuButton'
              onClick={() => setIsOpen(true)}
              aria-label="Abrir menu"
            >
              <span />
              <span />
              <span />
            </button>
          </div>

          {/* RIGHT / MENU DESKTOP */}
          <nav className='desktopNav'>
            <ul>
              {menuItems.map((item) => (
                <li key={item.label}>
                  <Link href={item.href}>
                    {item.label}
                  </Link>
                </li>
              ))}
            </ul>
          </nav>
        </div>
      </header>

      {/* OVERLAY */}
      <div
        className={`overlay ${isOpen ? 'overlayActive' : ''
          }`}
        onClick={() => setIsOpen(false)}
      />

      {/* SIDEBAR */}
      <aside className={`sidebar ${isOpen ? 'sidebarActive' : ''}`}>
        <div>
          <div className='sidebarHeader'>
            <div className='logoIcon'>
              <div className='logoShape'>
                <div className='blockLeft' />
                <div className='blockCenter' />
                <div className='blockRight' />
              </div>
            </div>

            <button
              onClick={() => setIsOpen(false)}
              aria-label="Fechar menu"
            >
              <IoClose size={28} />
            </button>
          </div>

          <nav className='mobileNav'>
            <ul>
              {menuItems.map((item) => (
                <li key={item.label}>
                  <Link
                    href={item.href}
                    onClick={() => setIsOpen(false)}
                  >
                    {item.label}
                  </Link>
                </li>
              ))}
            </ul>
          </nav>
        </div>

        {/* SOCIALS */}
        <div className='socials'>
          <Link href="#" aria-label="Instagram">
            <FaInstagram size={24} />
          </Link>

          <Link href="#" aria-label="LinkedIn">
            <FaLinkedinIn size={24} />
          </Link>
        </div>
      </aside>
    </>
  );
}